type Vec3 = {x: number; y: number; z: number};
type Projected = Vec3 & {sx: number; sy: number};

const clamp = (value: number, min = 0, max = 1) =>
  Math.min(max, Math.max(min, value));

const mod = (value: number, divisor: number) =>
  ((value % divisor) + divisor) % divisor;

const cycle = (frame: number, period: number, offset = 0) =>
  mod(frame + offset, period) / period;

const smoothRange = (value: number, input: [number, number]) =>
  interpolate(value, input, [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.bezier(0.22, 1, 0.36, 1),
  });

const spreadRange = (value: number, input: [number, number]) =>
  interpolate(value, input, [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.inOut(Easing.cubic),
  });

const smoothstep = (value: number) => {
  const t = clamp(value);
  return t * t * (3 - 2 * t);
};

const roundHalf = (value: number) => Math.round(value * 2) / 2;

const vectorFromLonLat = (lon: number, lat: number): Vec3 => {
  const lambda = lon * DEG;
  const phi = lat * DEG;
  const cosPhi = Math.cos(phi);
  return {
    x: cosPhi * Math.sin(lambda),
    y: Math.sin(phi),
    z: cosPhi * Math.cos(lambda),
  };
};

const normalize = (vector: Vec3): Vec3 => {
  const length = Math.hypot(vector.x, vector.y, vector.z) || 1;
  return {x: vector.x / length, y: vector.y / length, z: vector.z / length};
};

const slerp = (from: Vec3, to: Vec3, t: number): Vec3 => {
  const dot = clamp(from.x * to.x + from.y * to.y + from.z * to.z, -1, 1);
  const omega = Math.acos(dot);
  const sinOmega = Math.sin(omega);
  if (sinOmega < 0.0001) {
    return normalize({
      x: from.x + (to.x - from.x) * t,
      y: from.y + (to.y - from.y) * t,
      z: from.z + (to.z - from.z) * t,
    });
  }
  const a = Math.sin((1 - t) * omega) / sinOmega;
  const b = Math.sin(t * omega) / sinOmega;
  return {
    x: from.x * a + to.x * b,
    y: from.y * a + to.y * b,
    z: from.z * a + to.z * b,
  };
};

